Use **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory and gives you an `HttpClient` — no real port, no real server.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
```

### Example test class

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/list",
            @params = new { }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

### Key points

| Concern | Approach |
|---|---|
| **No real server** | `WebApplicationFactory` runs Kestrel in-memory |
| **Override services** | Call `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap dependencies (e.g., mock a DB) |
| **Stateful sessions** | If your server uses Streamable HTTP with session tokens, capture the `Mcp-Session-Id` header from `initialize` and send it on subsequent requests |
| **SSE streaming** | Read the response stream with `GetStreamAsync` and parse `text/event-stream` lines |
| **`Program` visibility** | If `Program` is implicit (top-level statements), add `public partial class Program { }` at the bottom of `Program.cs` |

This gives you full HTTP-fidelity tests (headers, status codes, content negotiation) with in-process speed.
